package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.Excluder;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class GsonExcluderTest {

  private Gson gson;

  @BeforeEach
  public void setUp() throws Exception {
    gson = new Gson();

    // Use reflection to set the private final excluder field if null (for coverage)
    Field excluderField = Gson.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    Excluder excluderInstance = (Excluder) excluderField.get(gson);
    if (excluderInstance == null) {
      Excluder mockExcluder = mock(Excluder.class);

      // Remove final modifier via reflection
      Field modifiersField = Field.class.getDeclaredField("modifiers");
      modifiersField.setAccessible(true);
      modifiersField.setInt(excluderField, excluderField.getModifiers() & ~Modifier.FINAL);

      excluderField.set(gson, mockExcluder);
    }
  }

  @Test
  public void testExcluderReturnsExcluderInstance() {
    Excluder excluder = gson.excluder();
    assertNotNull(excluder, "excluder() should not return null");
  }

  @Test
  public void testExcluderIsSameOnMultipleCalls() {
    Excluder first = gson.excluder();
    Excluder second = gson.excluder();
    assertSame(first, second, "excluder() should return the same instance on multiple calls");
  }
}
